from functools import wraps
import time

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

# Elasticsearch configuration
ES_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ES_PORT = int(os.environ.get('ELASTICSEARCH_PORT', 9200))
ES_USERNAME = os.environ.get('ELASTICSEARCH_USERNAME', None)
ES_PASSWORD = os.environ.get('ELASTICSEARCH_PASSWORD', None)
ES_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')

# Connection pool size for high traffic
ES_MAX_RETRIES = 3
ES_RETRY_ON_TIMEOUT = True
ES_TIMEOUT = 10


def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    kwargs = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'max_retries': ES_MAX_RETRIES,
        'retry_on_timeout': ES_RETRY_ON_TIMEOUT,
        'timeout': ES_TIMEOUT,
        'maxsize': 25,  # Connection pool size per node for high traffic
    }

    if ES_USERNAME and ES_PASSWORD:
        kwargs['basic_auth'] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**kwargs)


# Initialize ES client at module level for connection reuse
es_client = get_es_client()


def require_query_param(f):
    """Decorator to validate required query parameter."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        query = request.args.get('q', '').strip()
        if not query:
            return jsonify({
                'error': 'Missing or empty query parameter "q"',
                'status': 'error'
            }), 400
        if len(query) > 500:
            return jsonify({
                'error': 'Query parameter "q" exceeds maximum length of 500 characters',
                'status': 'error'
            }), 400
        return f(*args, **kwargs)
    return decorated_function


def build_search_query(keyword, page, per_page, sort_by, category, min_price, max_price):
    """Build Elasticsearch query with filters, pagination, and sorting."""
    must_clauses = [
        {
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',          # Boost product name matches
                    'name.autocomplete^2',
                    'description',
                    'category^2',
                    'brand^2',
                    'tags'
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%'
            }
        }
    ]

    filter_clauses = []

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    price_range = {}
    if min_price is not None:
        price_range['gte'] = min_price
    if max_price is not None:
        price_range['lte'] = max_price
    if price_range:
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # Only show available/active products
    filter_clauses.append({
        'term': {'is_active': True}
    })

    query = {
        'query': {
            'bool': {
                'must': must_clauses,
                'filter': filter_clauses
            }
        },
        'from': (page - 1) * per_page,
        'size': per_page,
        'highlight': {
            'fields': {
                'name': {'number_of_fragments': 1},
                'description': {'number_of_fragments': 2, 'fragment_size': 150}
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>']
        },
        'aggs': {
            'categories': {
                'terms': {
                    'field': 'category.keyword',
                    'size': 20
                }
            },
            'brands': {
                'terms': {
                    'field': 'brand.keyword',
                    'size': 20
                }
            },
            'price_ranges': {
                'range': {
                    'field': 'price',
                    'ranges': [
                        {'key': 'under_25', 'to': 25},
                        {'key': '25_to_50', 'from': 25, 'to': 50},
                        {'key': '50_to_100', 'from': 50, 'to': 100},
                        {'key': '100_to_200', 'from': 100, 'to': 200},
                        {'key': 'over_200', 'from': 200}
                    ]
                }
            },
            'avg_price': {
                'avg': {'field': 'price'}
            }
        },
        '_source': [
            'name', 'description', 'price', 'category', 'brand',
            'image_url', 'rating', 'review_count', 'in_stock', 'sku'
        ]
    }

    # Sorting
    if sort_by == 'price_asc':
        query['sort'] = [{'price': 'asc'}, '_score']
    elif sort_by == 'price_desc':
        query['sort'] = [{'price': 'desc'}, '_score']
    elif sort_by == 'rating':
        query['sort'] = [{'rating': 'desc'}, '_score']
    elif sort_by == 'newest':
        query['sort'] = [{'created_at': 'desc'}, '_score']
    else:
        # Default: relevance (score-based)
        query['sort'] = ['_score', {'rating': 'desc'}]

    # Add suggest for typo correction
    query['suggest'] = {
        'text': keyword,
        'product_suggestion': {
            'phrase': {
                'field': 'name.trigram',
                'size': 3,
                'gram_size': 3,
                'direct_generator': [{
                    'field': 'name.trigram',
                    'suggest_mode': 'popular'
                }],
                'highlight': {
                    'pre_tag': '<em>',
                    'post_tag': '</em>'
                }
            }
        }
    }

    return query


def format_search_results(response, page, per_page):
    """Format Elasticsearch response into a clean API response."""
    hits = response.get('hits', {})
    total = hits.get('total', {}).get('value', 0)
    total_relation = hits.get('total', {}).get('relation', 'eq')

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit.get('_id')
        product['score'] = hit.get('_score')

        # Include highlights if available
        highlights = hit.get('highlight', {})
        if highlights:
            product['highlights'] = highlights

        products.append(product)

    # Format aggregations
    aggregations = response.get('aggregations', {})
    facets = {}

    if 'categories' in aggregations:
        facets['categories'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggregations['categories'].get('buckets', [])
        ]

    if 'brands' in aggregations:
        facets['brands'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggregations['brands'].get('buckets', [])
        ]

    if 'price_ranges' in aggregations:
        facets['price_ranges'] = [
            {'range': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggregations['price_ranges'].get('buckets', [])
        ]

    if 'avg_price' in aggregations:
        avg_price = aggregations['avg_price'].get('value')
        if avg_price is not None:
            facets['avg_price'] = round(avg_price, 2)

    # Format suggestions
    suggestions = []
    suggest_data = response.get('suggest', {}).get('product_suggestion', [])
    for suggestion in suggest_data:
        for option in suggestion.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'highlighted': option.get('highlighted'),
                'score': option.get('score')
            })

    # Pagination metadata
    total_pages = (total + per_page - 1) // per_page if total > 0 else 0

    result = {
        'status': 'success',
        'data': {
            'products': products,
            'pagination': {
                'total': total,
                'total_relation': total_relation,
                'page': page,
                'per_page': per_page,
                'total_pages': total_pages,
                'has_next': page < total_pages,
                'has_prev': page > 1
            },
            'facets': facets
        }
    }

    if suggestions:
        result['data']['suggestions'] = suggestions

    return result


@app.route('/api/search', methods=['GET'])
@require_query_param
def search_products():
    """
    Search products by keyword.

    Query Parameters:
        q (str): Search keyword (required)
        page (int): Page number (default: 1)
        per_page (int): Results per page (default: 20, max: 100)
        sort (str): Sort order - relevance, price_asc, price_desc, rating, newest
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter

    Returns:
        JSON response with matching products, pagination info, facets, and suggestions.
    """
    start_time = time.time()

    # Parse query parameters
    keyword = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    sort_by = request.args.get('sort', 'relevance')
    category = request.args.get('category', None)
    min_price = request.args.get('min_price', None, type=float)
    max_price = request.args.get('max_price', None, type=float)

    # Validate pagination parameters
    page = max(1, page)
    per_page = max(1, min(per_page, 100))  # Cap at 100 results per page

    # Validate sort parameter
    valid_sorts = ['relevance', 'price_asc', 'price_desc', 'rating', 'newest']
    if sort_by not in valid_sorts:
        sort_by = 'relevance'

    # Validate price range
    if min_price is not None and min_price < 0:
        min_price = 0
    if max_price is not None and max_price < 0:
        max_price = None
    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({
            'error': 'min_price cannot be greater than max_price',
            'status': 'error'
        }), 400

    try:
        # Build and execute search query
        search_query = build_search_query(
            keyword=keyword,
            page=page,
            per_page=per_page,
            sort_by=sort_by,
            category=category,
            min_price=min_price,
            max_price=max_price
        )

        logger.info(f"Searching for: '{keyword}' (page={page}, per_page={per_page}, sort={sort_by})")

        response = es_client.search(
            index=ES_INDEX,
            body=search_query,
            request_timeout=ES_TIMEOUT
        )

        # Format results
        result = format_search_results(response, page, per_page)

        # Add timing information
        elapsed_ms = round((time.time() - start_time) * 1000, 2)
        es_took_ms = response.get('took', 0)
        result['meta'] = {
            'query': keyword,
            'took_ms': elapsed_ms,
            'es_took_ms': es_took_ms
        }

        logger.info(
            f"Search for '{keyword}' returned {result['data']['pagination']['total']} results "
            f"in {elapsed_ms}ms (ES: {es_took_ms}ms)"
        )

        return jsonify(result), 200

    except Exception as e:
        logger.error(f"Search error for query '{keyword}': {str(e)}", exc_info=True)

        # Check for specific Elasticsearch errors
        error_message = 'An error occurred while searching'
        status_code = 500

        error_str = str(e).lower()
        if 'connection' in error_str or 'timeout' in error_str:
            error_message = 'Search service is temporarily unavailable. Please try again.'
            status_code = 503
        elif 'index_not_found' in error_str:
            error_message = 'Search index not found. Please contact support.'
            status_code = 500

        return jsonify({
            'status': 'error',
            'error': error_message
        }), status_code


@app.route('/api/search/suggest', methods=['GET'])
def search_suggest():
    """
    Autocomplete/suggest endpoint for search-as-you-type functionality.

    Query Parameters:
        q (str): Partial search keyword (required)
        limit (int): Max suggestions (default: 5, max: 10)
    """
    keyword = request.args.get('q', '').strip()
    limit = request.args.get('limit', 5, type=int)
    limit = max(1, min(limit, 10))

    if not keyword or len(keyword) < 2:
        return jsonify({
            'status': 'success',
            'data': {'suggestions': []}
        }), 200

    try:
        query = {
            'size': 0,
            'suggest': {
                'product_suggest': {
                    'prefix': keyword,
                    'completion': {
                        'field': 'name.suggest',
                        'size': limit,
                        'skip_duplicates': True,
                        'fuzzy': {
                            'fuzziness': 'AUTO'
                        }
                    }
                }
            }
        }

        response = es_client.search(
            index=ES_INDEX,
            body=query,
            request_timeout=5  # Shorter timeout for suggestions
        )

        suggestions = []
        suggest_data = response.get('suggest', {}).get('product_suggest', [])
        for suggestion in suggest_data:
            for option in suggestion.get('options', []):
                suggestions.append({
                    'text': option.get('text'),
                    'score': option.get('_score'),
                    'id': option.get('_id')
                })

        return jsonify({
            'status': 'success',
            'data': {'suggestions': suggestions}
        }), 200

    except Exception as e:
        logger.error(f"Suggest error for query '{keyword}': {str(e)}")
        return jsonify({
            'status': 'error',
            'error': 'Suggestion service temporarily unavailable'
        }), 503


